// Log-log linear interpolation of mu [1/cm] on the uniform energy grid.
// gas: "N2" | "He" | "Ar" | "air"; kind: "photo" | "incoh" | "total".
// E_keV outside 5-25 keV is clamped to the table edge.
function gasMuInterp(gas, E_keV, kind) {
  var tbl = GASMU_TABLES[gas];
  if (!tbl || !tbl[kind]) return NaN;
  var arr = tbl[kind];
  var n = GASMU_TABLES.N, e0 = GASMU_TABLES.E_min_keV, de = GASMU_TABLES.E_step_keV;
  var e = E_keV;
  if (!(e > 0)) return NaN;
  var eMax = e0 + de * (n - 1);
  if (e < e0) e = e0;
  if (e > eMax) e = eMax;
  var idx = (e - e0) / de;
  var i = Math.floor(idx);
  if (i >= n - 1) i = n - 2;
  var ea = e0 + de * i, eb = ea + de;
  var t = (Math.log(e) - Math.log(ea)) / (Math.log(eb) - Math.log(ea));
  if (t < 0) t = 0;
  if (t > 1) t = 1;
  return Math.exp(Math.log(arr[i]) * (1 - t) + Math.log(arr[i + 1]) * t);
}

